from pathlib import Path
import cv2
import torch
from torch.utils.data import Dataset

class LichenDataset(Dataset):
    def __init__(self, image_dir, mask_dir, image_size=512):
        self.image_dir = Path(image_dir)
        self.mask_dir = Path(mask_dir)
        self.image_size = image_size

        # how to look up masks
        mask_lookup = {
            p.stem: p
            for p in self.mask_dir.rglob("*")
            if p.suffix.lower() == ".png"
        }

        self.pairs = []

        for image_path in self.image_dir.rglob("*"):
            if image_path.suffix.lower() not in [".png", ".jpg", ".jpeg"]:
               continue
            mask_path = mask_lookup.get(image_path.stem)
            
            if mask_path is not None:
                self.pairs.append((image_path, mask_path))

        if len(self.pairs) == 0:
            raise RuntimeError("no pairs found")

        print(f"Number of pairs found: {len(self.pairs)}")

    def __len__(self):
        return len(self.pairs)

    def __getitem__(self, index):
        image_path, mask_path = self.pairs[index]

        # load the image
        image = cv2.imread(str(image_path))
        if image is None:
            raise RuntimeError(f"Failed to load image: {image_path}")

        image = cv2.cvtColor(image, cv2.COLOR_BGR2RGB)

        # load the mask
        mask = cv2.imread(str(mask_path), cv2.IMREAD_GRAYSCALE)
        if mask is None:
            raise RuntimeError(f"Failed to load mask: {mask_path}")

        # make sizes match
        image = cv2.resize(image, (self.image_size, self.image_size))
        mask = cv2.resize(mask, (self.image_size, self.image_size),
                          interpolation=cv2.INTER_NEAREST)

        # normalize image
        image = image.astype("float32") / 255.0

        # make sure mask binary
        mask = (mask > 0).astype("float32")

        # to tensor
        image = torch.from_numpy(image).permute(2, 0, 1)
        mask = torch.from_numpy(mask).unsqueeze(0)


        # preserve filename
        image_name = image_path.stem

        return image, mask, image_name